def binary_search(sorted_list: list[int], target: int) -> int:
    low = 0
    high = len(sorted_list) - 1

    while low <= high:
        mid = low + (high - low) // 2
        guess = sorted_list[mid]

        if guess == target:
            return mid
        elif guess < target:
            low = mid + 1
        else:
            high = mid - 1

    return -1

